import{c as e,Q as a,j as o,m as r}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Email Logs","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/email-logs.md","filePath":"guide/admin/email-logs.md","lastUpdated":1778862269000}'),n={name:"guide/admin/email-logs.md"};function i(s,t,l,d,h,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="email-logs" tabindex="-1">Email Logs <a class="header-anchor" href="#email-logs" aria-label="Permalink to &quot;Email Logs&quot;">​</a></h1><p>The <strong>Email Logs</strong> page is the dispatch history for every outbound notification — emails, webhooks, and in-app messages. Use it when a customer says &quot;I didn&#39;t get the invite email&quot; or &quot;the password reset never arrived.&quot;</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li>Header with title, description, and (in development mode) a <strong>Send Sample Emails</strong> button.</li><li>Toolbar with channel filter, status filter, search, <strong>Clear</strong>, count, and a time-range toggle.</li><li>Table of dispatches.</li></ul><h2 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Channel</strong></td><td>All / Email / Webhook / In-App.</td></tr><tr><td><strong>Status</strong></td><td>All / Sent / Pending / Failed / Bounced.</td></tr><tr><td><strong>Search</strong></td><td>Free text across subject, template slug, recipient IDP ID, channel, status, error message.</td></tr><tr><td><strong>Clear</strong></td><td>Resets all filters and the search.</td></tr><tr><td>Count</td><td>&quot;N of M&quot; — filtered vs. total.</td></tr></tbody></table><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Channel</strong></td><td>Email / Webhook / In-App badge.</td></tr><tr><td><strong>Status</strong></td><td>Sent / Pending / Failed / Bounced badge.</td></tr><tr><td><strong>Template</strong></td><td>Template slug in monospace (e.g. <code>user_invite</code>).</td></tr><tr><td><strong>Subject</strong></td><td>Email subject or event description, truncated.</td></tr><tr><td><strong>Recipient</strong></td><td>User avatar if an IDP ID is available; dash otherwise.</td></tr><tr><td><strong>Error</strong></td><td>Error message in red if the dispatch failed; dash otherwise.</td></tr><tr><td><strong>Sent At</strong></td><td>When dispatched.</td></tr><tr><td><strong>Created</strong></td><td>When the log entry was created.</td></tr></tbody></table><p>The table loads the most recent 200 records — there is no pagination.</p><h2 id="send-sample-emails" tabindex="-1">Send Sample Emails <a class="header-anchor" href="#send-sample-emails" aria-label="Permalink to &quot;Send Sample Emails&quot;">​</a></h2><p>The <strong>Send Sample Emails</strong> button appears only when mock data is enabled in the deployment — it is intended for development and demo environments, where it triggers a batch of sample notifications so you can verify the templates render correctly.</p><p>In production, the button is not visible.</p><h2 id="typical-investigations" tabindex="-1">Typical investigations <a class="header-anchor" href="#typical-investigations" aria-label="Permalink to &quot;Typical investigations&quot;">​</a></h2><ul><li><strong>&quot;User didn&#39;t receive their invite&quot;</strong> — filter Template = <code>user_invite</code>, search the recipient name. If <code>status</code> is Sent, the email went out — check spam folder. If Failed, look at the error.</li><li><strong>&quot;Webhook delivery failed&quot;</strong> — filter Channel = Webhook, Status = Failed. The error column shows what went wrong.</li><li><strong>&quot;In-app notification missing&quot;</strong> — filter Channel = In-App. If absent, the notification was never enqueued.</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The table is a flat list with no row-click action; it is purely informational.</li><li>Sent does not guarantee Delivered. Bounces show up in the Bounced status if the email provider reports them back.</li><li>Error text is the raw error from the upstream provider. Long errors are truncated; copy-paste from the cell to read the full text.</li><li>The page does not auto-refresh. Reload to see new entries.</li></ul>',16)])])}const g=e(n,[["render",i]]);export{m as __pageData,g as default};
